@dataclass
class FusionDeliberationState:
    """Accumulates the verbatim /responses event stream for the embed."""

    events: list[dict] = field(default_factory=list)
    fusion_index: int | None = None
    seen_roster: bool = False
    seen_analysis_started: bool = False
    seen_analysis_done: bool = False
    completed: bool = False

    def record(self, event: dict) -> str | None:
        """Append the event; return a milestone key if it should trigger a new
        snapshot, else None."""
        if not isinstance(event, dict):
            return None
        etype = event.get("type")
        if not isinstance(etype, str):
            return None

        item = event.get("item")
        item_type = item.get("type") if isinstance(item, dict) else None

        if etype == "response.output_item.added":
            if item_type == "openrouter:fusion":
                if self.fusion_index is not None:
                    return None
                self.fusion_index = event.get("output_index")
                self.events.append(event)
                return "fusion_open"
            self.events.append(event)
            return None

        if etype == "response.output_item.done":
            if item_type != "openrouter:fusion":
                self.events.append(event)
            return None

        if etype == "response.fusion_call.in_progress":
            self.seen_roster = True
            self.events.append(event)
            return "roster"

        if etype == "response.fusion_call.panel.added":
            first = not self.seen_roster
            self.seen_roster = True
            self.events.append(event)
            return "roster" if first else "panels"

        if etype == "response.fusion_call.panel.completed":
            self.events.append(event)
            return "panels"

        if etype == "response.fusion_call.analysis.in_progress":
            self.seen_analysis_started = True
            self.events.append(event)
            return "analysis_start"

        if etype == "response.fusion_call.analysis.completed":
            self.seen_analysis_done = True
            self.events.append(event)
            return "analysis_done"

        if etype == "response.fusion_call.completed":
            self.events.append(event)
            return None

        if etype in ("response.completed", "response.done"):
            self.completed = True
            self.events.append(event)
            return "completed"

        if etype.startswith("response.output_text"):
            self.events.append(event)
            if (
                etype == "response.output_text.done"
                and self.fusion_index is not None
                and isinstance(event.get("output_index"), int)
                and event["output_index"] > self.fusion_index
            ):
                return "answer"
            return None

        if etype in ("response.created", "response.in_progress"):
            self.events.append(event)
            return None

        self.events.append(event)
        return None

    def synthesize_missing_analysis(self) -> bool:
        if not self.seen_analysis_started or self.seen_analysis_done:
            return False
        synthetic = {
            "type": "response.fusion_call.analysis.completed",
            "output_index": self.fusion_index,
            "analysis": {
                "consensus": [],
                "contradictions": [],
                "partial_coverage": [],
                "unique_insights": [],
                "blind_spots": [],
            },
        }
        pos = next(
            (
                i
                for i in range(len(self.events) - 1, -1, -1)
                if isinstance(self.events[i], dict)
                and self.events[i].get("type") in ("response.completed", "response.done")
            ),
            len(self.events),
        )
        self.events.insert(pos, synthetic)
        self.seen_analysis_done = True
        return True


def build_fusion_embed_html(
    state: FusionDeliberationState, model_names: dict[str, str] | None = None,
    *, final: bool = False,
) -> str:
    """Render the embed HTML with state.events (and catalog display names) injected."""
    payload = (
        json.dumps(state.events, default=str)
        .replace("<", "\\u003c")
        .replace(">", "\\u003e")
        .replace("&", "\\u0026")
    )
    names_payload = (
        json.dumps(model_names or {}, default=str)
        .replace("<", "\\u003c")
        .replace(">", "\\u003e")
        .replace("&", "\\u0026")
    )
    html = _FUSION_TEMPLATE_HTML.replace("/*__FUSION_EVENTS_JSON__*/[]", payload, 1)
    html = html.replace("/*__FUSION_NAMES_JSON__*/{}", names_payload, 1)
    return html.replace("/*__FUSION_FINAL__*/false", "true" if final else "false", 1)
